// 分析类型（节点名称）\n  analysisType   String    @map(\"analysis_type\") @db.VarChar(100)\n  /// 分析结果（Markdown 格式）\n  analysisResult String?   @map(\"analysis_result\") @db.Text\n  /// 还原后的结果（解密后的内容）\n  originalResult String?   @map(\"original_result\") @db.Text\n  /// 版本号\n  version        Int       @default(1)\n  /// 分析状态：1-进行中，2-已完成，3-已失败\n  status         Int       @default(1)\n  /// 是否为激活版本（同一 caseId+nodeId 只有一条为 true）\n  isActive       Boolean   @default(false) @map(\"is_active\")\n  /// 积分是否已扣减\n  pointDeducted  Boolean   @default(false) @map(\"point_deducted\")\n  /// 消耗的千 token 数（积分扣减单位）\n  tokenCount     Int?      @map(\"token_count\")\n  /// 实际 token 总数\n  tokens         Int?\n  /// 创建时间\n  createdAt      DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt      DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt      DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的案件\n  case cases @relation(fields: [caseId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的会话\n  caseSession caseSessions @relation(fields: [sessionId], references: [sessionId], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的节点\n  node nodes @relation(fields: [nodeId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([caseId], map: \"idx_case_analyses_case_id\")\n  @@index([sessionId], map: \"idx_case_analyses_session_id\")\n  @@index([nodeId], map: \"idx_case_analyses_node_id\")\n  @@index([analysisType], map: \"idx_case_analyses_analysis_type\")\n  @@index([status], map: \"idx_case_analyses_status\")\n  @@index([caseId, nodeId, isActive], map: \"idx_case_analyses_active_version\")\n  @@index([deletedAt], map: \"idx_case_analyses_deleted_at\")\n  @@map(\"case_analyses\")\n}\n\n/// 示范案例表 - 存储预设的示范案例，供用户快速体验分析流程\nmodel demoCases {\n  /// 示范案例ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 案例标题\n  title       String    @db.VarChar(200)\n  /// 案例简介\n  description String?   @db.VarChar(500)\n  /// 示范案例的文本案情描述（点击后填入用户输入框）\n  content     String?   @db.Text\n  /// 案件类型ID\n  caseTypeId  Int       @map(\"case_type_id\")\n  /// 预设材料列表（JSON 数组）\n  materials   Json      @default(\"[]\")\n  /// 封面图片 URL\n  coverImage  String?   @map(\"cover_image\") @db.VarChar(500)\n  /// 排序优先级，数字越小越靠前\n  priority    Int       @default(100)\n  /// 状态：1-启用，0-禁用\n  status      Int       @default(1)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的案件类型\n  caseType caseTypes @relation(fields: [caseTypeId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([caseTypeId], map: \"idx_demo_cases_case_type_id\")\n  @@index([priority], map: \"idx_demo_cases_priority\")\n  @@index([status], map: \"idx_demo_cases_status\")\n  @@index([deletedAt], map: \"idx_demo_cases_deleted_at\")\n  @@map(\"demo_cases\")\n}\n\n/// 案件材料向量表 - 存储案件材料的向量化数据用于语义检索\n/// 使用 pgvector 扩展进行向量存储和相似度搜索\n/// 注意：此表结构不允许修改，必须保持原有设计\nmodel caseMaterialEmbeddings {\n  /// 主键，UUID 类型\n  id        String                   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  /// 材料内容片段\n  text      String?                  @db.Text\n  /// 元数据（JSON 格式，包含 caseId、materialId、sessionId、materialName、materialType、chunkIndex）\n  metadata  Json?\n  /// 材料内容向量嵌入\n  embedding Unsupported(\"vector\")?\n  /// 中文全文搜索向量（由 trigger 自动维护）\n  tsv       Unsupported(\"tsvector\")?\n\n  @@index([tsv], type: Gin, map: \"idx_case_material_tsv\")\n  @@map(\"case_material_embeddings\")\n}\n\n/// OSS 文件表\nmodel ossFiles {\n  /// ID，主键，自增\n  id               Int       @id @default(autoincrement())\n  /// 关联的用户ID，外键关联用户表\n  userId           Int       @map(\"user_id\")\n  /// 存储桶名称 \n  bucketName       String    @map(\"bucket_name\") @db.VarChar(100)\n  /// 文件名称\n  fileName         String    @map(\"file_name\") @db.VarChar(255)\n  /// 文件在 OSS 中的路径\n  filePath         String?   @map(\"file_path\") @db.VarChar(500)\n  /// 文件大小(字节)\n  fileSize         Decimal   @map(\"file_size\") @db.Decimal(15, 2)\n  /// 文件MIME类型\n  fileType         String    @map(\"file_type\") @db.VarChar(100)\n  /// 文件的md5值\n  fileMd5          String?   @map(\"file_md5\") @db.VarChar(32)\n  /// 文件来源\n  source           String?\n  /// 文件状态\n  status           Int       @default(0) @map(\"status\")\n  /// 是否加密\n  encrypted        Boolean   @default(false) @map(\"encrypted\")\n  /// 原始 MIME 类型（加密文件需要）\n  originalMimeType String?   @map(\"original_mime_type\") @db.VarChar(100)\n  /// 创建时间\n  createdAt        DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt        DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt        DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  // 示范案例克隆场景的去重联合键：同一用户下同一 OSS 对象（bucket+path）只能有一行\n  // 显式指定约束名，便于排查 P2002 错误时通过 err.meta.target 识别冲突来源\n  @@unique([userId, bucketName, filePath], map: \"idx_oss_files_user_bucket_path\")\n  @@index([userId], map: \"idx_oss_files_user_id\")\n  @@index([bucketName], map: \"idx_oss_files_bucket_name\")\n  @@index([fileName], map: \"idx_oss_files_file_name\")\n  @@index([fileType], map: \"idx_oss_files_file_type\")\n  @@index([status], map: \"idx_oss_files_status\")\n  @@index([deletedAt], map: \"idx_oss_files_deleted_at\")\n  @@index([encrypted], map: \"idx_oss_files_encrypted\")\n  @@map(\"oss_files\")\n}\n\n/// 法律主表 - 存储法律法规的基本信息\nmodel legalMain {\n  /// 主键，使用 UUID v7\n  id               String          @id @default(uuid(7))\n  /// 法律名称\n  name             String\n  /// 法律代码\n  code             String\n  /// 法律类型：law(法律)、regulation(行政法规)、judicial_interp(司法解释)、guideline(指导意见)\n  type             String\n  /// 法律分类\n  category         String?\n  /// 法律内容\n  content          String          @db.Text\n  /// 发文机关\n  issuingAuthority String?         @map(\"issuing_authority\")\n  /// 文号\n  documentNumber   String?         @map(\"document_number\")\n  /// 法律发布日期\n  publishDate      DateTime?       @map(\"publish_date\") @db.Date\n  /// 法律生效日期\n  effectiveDate    DateTime?       @map(\"effective_date\") @db.Date\n  /// 法律失效日期\n  invalidDate      DateTime?       @map(\"invalid_date\") @db.Date\n  /// 最后编辑时间\n  lastEditedAt     DateTime?       @default(now()) @map(\"last_edited_at\") @db.Timestamptz()\n  /// 最后嵌入时间\n  lastEmbeddingAt  DateTime?       @map(\"last_embedding_at\") @db.Timestamptz()\n  /// 创建时间\n  createdAt        DateTime?       @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 最后更新时间\n  updatedAt        DateTime?       @default(now()) @updatedAt @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt        DateTime?       @map(\"deleted_at\") @db.Timestamptz()\n  /// 法律条文关联\n  legalArticles    legalArticles[]\n\n  @@index([type], map: \"idx_legal_main_type\")\n  @@index([code], map: \"idx_legal_main_code\")\n  @@index([issuingAuthority], map: \"idx_legal_main_issuing_authority\")\n  @@index([deletedAt], map: \"idx_legal_main_deleted_at\")\n  @@map(\"legal_main\")\n}\n\n/// 法律条文表 - 存储法律法规对应的具体条款内容\nmodel legalArticles {\n  /// 主键，使用 UUID v7\n  id              String    @id @default(uuid(7))\n  /// 法律 ID，关联法律主表\n  legalId         String    @map(\"legal_id\")\n  /// 条文类型：notice(通知)、header(正文头部)、footer(正文尾部)、annex(附件)、l1-l5(各级标题)\n  type            String\n  /// 一级标题(编)\n  l1              String?\n  /// 一级标题序号\n  l1I             Int?      @map(\"l1_i\")\n  /// 二级标题(分编)\n  l2              String?\n  /// 二级标题序号\n  l2I             Int?      @map(\"l2_i\")\n  /// 三级标题(章)\n  l3              String?\n  /// 三级标题序号\n  l3I             Int?      @map(\"l3_i\")\n  /// 四级标题(节)\n  l4              String?\n  /// 四级标题序号\n  l4I             Int?      @map(\"l4_i\")\n  /// 五级标题(条)\n  l5              String?\n  /// 五级标题序号\n  l5I             Int?      @map(\"l5_i\")\n  /// 块排序\n  order           Int?\n  /// 法律条文内容\n  content         String?   @db.Text\n  /// 法律条文发布日期\n  publishDate     DateTime? @map(\"publish_date\") @db.Date\n  /// 法律条文生效日期\n  effectiveDate   DateTime? @map(\"effective_date\") @db.Date\n  /// 法律条文失效日期\n  invalidDate     DateTime? @map(\"invalid_date\") @db.Date\n  /// 最后编辑时间\n  lastEditedAt    DateTime? @default(now()) @map(\"last_edited_at\") @db.Timestamptz()\n  /// 最后嵌入时间\n  lastEmbeddingAt DateTime? @map(\"last_embedding_at\") @db.Timestamptz()\n  /// 创建时间\n  createdAt       DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 最后更新时间\n  updatedAt       DateTime? @default(now()) @updatedAt @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz()\n  /// 法律主表关联\n  legalMain       legalMain @relation(fields: [legalId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([legalId], map: \"idx_legal_articles_legal_id\")\n  @@index([deletedAt], map: \"idx_legal_articles_deleted_at\")\n  @@map(\"legal_articles\")\n}\n\n/// 法条内容嵌入表 - 存储法律条文的向量化数据用于语义检索\n/// 注意：此表结构不允许修改，必须保持原有设计\nmodel lawEmbeddings {\n  /// 主键，UUID 类型\n  id        String                   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  /// 法律内容文本\n  text      String?                  @db.Text\n  /// 法律内容元数据（JSON 格式）\n  metadata  Json?\n  /// 法律内容向量嵌入\n  embedding Unsupported(\"vector\")?\n  /// 中文全文搜索向量（由 trigger 自动维护）\n  tsv       Unsupported(\"tsvector\")?\n\n  @@index([tsv], type: Gin, map: \"idx_law_embeddings_tsv\")\n  @@index([text(ops: raw(\"gin_trgm_ops\"))], type: Gin, map: \"idx_law_embeddings_text_trgm\")\n  @@map(\"law_embeddings\")\n}\n\n/// zhparser 扩展自动创建的自定义词典类型，不由 Prisma 管理\nenum dictType {\n  extra\n  it\n  edu\n  gov\n  medical\n  other\n\n  @@map(\"dict_type\")\n}\n\n/// zhparser 扩展自动创建的自定义词表，不由 Prisma 管理\nmodel pgTsCustomWord {\n  word   String   @id @map(\"word\") @db.Char(255)\n  tf     Float    @default(10.0) @map(\"tf\")\n  idf    Float    @default(2.0) @map(\"idf\")\n  attr   String   @default(\"n\") @map(\"attr\") @db.Char(1)\n  tsType dictType @default(extra) @map(\"ts_type\")\n\n  @@map(\"pg_ts_custom_word\")\n  @@ignore\n}\n\n// prisma/models/materials.prisma\n\n/// 文本内容记录表\n/// 对齐 docRecognitionRecords 结构，为 CASE_CONTENT 类型材料提供独立存储\nmodel textContentRecords {\n  /// 记录ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 用户ID\n  userId          Int       @map(\"user_id\")\n  /// 关联的案件ID\n  caseId          Int       @map(\"case_id\")\n  /// 关联的案件材料ID（可选，材料可能在关联前就创建）\n  materialId      Int?      @map(\"material_id\")\n  /// 文本内容（Markdown格式）\n  content         String?   @db.Text\n  /// HTML格式内容\n  htmlContent     String?   @map(\"html_content\") @db.Text\n  /// 处理状态：0-待处理 1-处理中 2-成功 3-失败\n  status          Int       @default(0)\n  /// 向量ID列表\n  vectorIds       Json?     @default(\"[]\") @map(\"vector_ids\")\n  /// 最后嵌入时间（非null表示已完成嵌入）\n  lastEmbeddingAt DateTime? @map(\"last_embedding_at\") @db.Timestamptz(6)\n  /// 创建时间\n  createdAt       DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt       DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间（软删除）\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  @@index([userId], map: \"idx_text_content_records_user_id\")\n  @@index([caseId], map: \"idx_text_content_records_case_id\")\n  @@index([materialId], map: \"idx_text_content_records_material_id\")\n  @@map(\"text_content_records\")\n}\n\n/// 会员级别表\nmodel membershipLevels {\n  /// 会员级别ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 级别名称\n  name        String    @db.VarChar(50)\n  /// 级别描述\n  description String?   @db.VarChar(255)\n  /// 排序顺序，数字越大级别越高\n  sortOrder   Int       @default(0) @map(\"sort_order\")\n  /// 状态：1-启用，0-禁用\n  status      Int       @default(1)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户会员记录\n  userMemberships    userMemberships[]\n  /// 关联的会员权益\n  membershipBenefits membershipBenefits[]\n  /// 关联的商品\n  products           products[]\n  /// 关联的兑换码\n  redemptionCodes    redemptionCodes[]\n  /// 关联的营销活动\n  campaigns          campaigns[]\n  /// 关联的会员节点权限\n  levelNodeAccess    levelNodeAccess[]\n\n  @@index([sortOrder], map: \"idx_membership_levels_sort_order\")\n  @@index([status], map: \"idx_membership_levels_status\")\n  @@index([deletedAt], map: \"idx_membership_levels_deleted_at\")\n  @@map(\"membership_levels\")\n}\n\n/// 用户会员记录表\nmodel userMemberships {\n  /// 用户会员记录ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 用户ID\n  userId       Int       @map(\"user_id\")\n  /// 会员级别ID\n  levelId      Int       @map(\"level_id\")\n  /// 开始日期\n  startDate    DateTime  @map(\"start_date\") @db.Timestamptz(6)\n  /// 到期日期\n  endDate      DateTime  @map(\"end_date\") @db.Timestamptz(6)\n  /// 是否自动续费\n  autoRenew    Boolean   @default(false) @map(\"auto_renew\")\n  /// 状态：1-有效，0-无效，2-已结算\n  status       Int       @default(1)\n  /// 结算时间（会员升级时记录）\n  settlementAt DateTime? @map(\"settlement_at\") @db.Timestamptz(6)\n  /// 来源类型：1-兑换码，2-直接购买，3-管理员赠送，4-活动奖励，5-试用，6-注册赠送，7-邀请注册赠送，8-会员升级\n  sourceType   Int       @map(\"source_type\")\n  /// 来源ID，根据来源类型关联到不同的表\n  sourceId     Int?      @map(\"source_id\")\n  /// 备注\n  remark       String?   @db.VarChar(255)\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user                         users                      @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的会员级别\n  level                        membershipLevels           @relation(fields: [levelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的积分记录\n  pointRecords                 pointRecords[]\n  /// 升级前的会员记录\n  membershipUpgradeRecordsFrom membershipUpgradeRecords[] @relation(\"FromMembership\")\n  /// 升级后的会员记录\n  membershipUpgradeRecordsTo   membershipUpgradeRecords[] @relation(\"ToMembership\")\n\n  @@index([userId], map: \"idx_user_memberships_user_id\")\n  @@index([levelId], map: \"idx_user_memberships_level_id\")\n  @@index([status], map: \"idx_user_memberships_status\")\n  @@index([endDate], map: \"idx_user_memberships_end_date\")\n  @@index([deletedAt], map: \"idx_user_memberships_deleted_at\")\n  @@map(\"user_memberships\")\n}\n\n/// 权益表\nmodel benefits {\n  /// 权益ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 权益唯一标识码（如 storage_space）\n  code            String    @unique @db.VarChar(50)\n  /// 权益名称\n  name            String    @db.VarChar(100)\n  /// 权益描述\n  description     String?   @db.VarChar(255)\n  /// 单位类型（byte-字节, count-次数）\n  unitType        String    @map(\"unit_type\") @db.VarChar(20)\n  /// 计算模式（sum-累加, max-取最大值）\n  consumptionMode String    @map(\"consumption_mode\") @db.VarChar(20)\n  /// 默认值（无会员用户的权益值）\n  defaultValue    BigInt    @default(0) @map(\"default_value\")\n  /// 状态：1-启用，0-禁用\n  status          Int       @default(1)\n  /// 创建时间\n  createdAt       DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt       DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的会员权益\n  membershipBenefits membershipBenefits[]\n  /// 关联的用户权益\n  userBenefits       userBenefits[]\n\n  @@index([code], map: \"idx_benefits_code\")\n  @@index([status], map: \"idx_benefits_status\")\n  @@index([deletedAt], map: \"idx_benefits_deleted_at\")\n  @@map(\"benefits\")\n}\n\n/// 会员权益关联表\nmodel membershipBenefits {\n  /// 会员权益关联ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 会员级别ID\n  levelId      Int       @map(\"level_id\")\n  /// 权益ID\n  benefitId    Int       @map(\"benefit_id\")\n  /// 权益值\n  benefitValue BigInt    @map(\"benefit_value\")\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的会员级别\n  level   membershipLevels @relation(fields: [levelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的权益\n  benefit benefits         @relation(fields: [benefitId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@unique([levelId, benefitId])\n  @@index([levelId], map: \"idx_membership_benefits_level_id\")\n  @@index([benefitId], map: \"idx_membership_benefits_benefit_id\")\n  @@index([deletedAt], map: \"idx_membership_benefits_deleted_at\")\n  @@map(\"membership_benefits\")\n}\n\n/// 用户权益记录表\nmodel userBenefits {\n  /// 用户权益记录ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 用户ID\n  userId       Int       @map(\"user_id\")\n  /// 权益ID\n  benefitId    Int       @map(\"benefit_id\")\n  /// 权益值\n  benefitValue BigInt    @map(\"benefit_value\")\n  /// 来源类型：membership_gift-会员赠送, benefit_package-权益包购买, redemption_code-兑换码, admin_gift-管理员赠送\n  sourceType   String    @map(\"source_type\") @db.VarChar(50)\n  /// 来源ID（关联到具体的会员记录、订单、兑换码等）\n  sourceId     Int?      @map(\"source_id\")\n  /// 生效时间\n  effectiveAt  DateTime  @map(\"effective_at\") @db.Timestamptz(6)\n  /// 过期时间\n  expiredAt    DateTime  @map(\"expired_at\") @db.Timestamptz(6)\n  /// 状态：1-有效，0-无效\n  status       Int       @default(1)\n  /// 备注\n  remark       String?   @db.VarChar(255)\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user    users    @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的权益\n  benefit benefits @relation(fields: [benefitId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_user_benefits_user_id\")\n  @@index([benefitId], map: \"idx_user_benefits_benefit_id\")\n  @@index([sourceType], map: \"idx_user_benefits_source_type\")\n  @@index([effectiveAt], map: \"idx_user_benefits_effective_at\")\n  @@index([expiredAt], map: \"idx_user_benefits_expired_at\")\n  @@index([status], map: \"idx_user_benefits_status\")\n  @@index([deletedAt], map: \"idx_user_benefits_deleted_at\")\n  @@map(\"user_benefits\")\n}\n\n/// 模型提供商表\nmodel modelProviders {\n  /// 模型提供商ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 模型提供商名称，唯一\n  name        String    @unique @db.VarChar(100)\n  /// 模型提供商API基础URL\n  baseUrl     String    @map(\"base_url\") @db.VarChar(255)\n  /// 模型提供商描述\n  description String?\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @updatedAt @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的 API 密钥\n  modelApiKeys modelApiKeys[]\n  /// 关联的模型\n  models       models[]\n\n  @@index([deletedAt], map: \"idx_model_providers_deleted_at\")\n  @@index([name], map: \"idx_model_providers_name\")\n  @@map(\"model_providers\")\n}\n\n/// 模型API密钥表\nmodel modelApiKeys {\n  /// 模型API密钥ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 关联的模型提供商ID\n  providerId   Int       @map(\"provider_id\")\n  /// API密钥名称\n  name         String    @db.VarChar(100)\n  /// API密钥值\n  apiKey       String    @map(\"api_key\") @db.VarChar(255)\n  /// 是否默认：true-是，false-否\n  isDefault    Boolean   @default(false) @map(\"is_default\")\n  /// 状态：1-启用，0-禁用\n  status       Int       @default(1)\n  /// 日调用限制次数\n  dailyLimit   Int?      @map(\"daily_limit\")\n  /// 月调用限制次数\n  monthlyLimit Int?      @map(\"monthly_limit\")\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @updatedAt @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的提供商\n  modelProvider modelProviders @relation(fields: [providerId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@unique([providerId, name])\n  @@index([providerId], map: \"idx_model_api_keys_provider_id\")\n  @@index([isDefault], map: \"idx_model_api_keys_is_default\")\n  @@index([status], map: \"idx_model_api_keys_status\")\n  @@index([deletedAt], map: \"idx_model_api_keys_deleted_at\")\n  @@map(\"model_api_keys\")\n}\n\n/// 模型配置表\nmodel models {\n  /// 模型ID，主键，自增\n  id                         Int       @id @default(autoincrement())\n  /// 关联的模型提供商ID\n  providerId                 Int       @map(\"provider_id\")\n  /// 模型名称\n  name                       String    @db.VarChar(100)\n  /// 模型显示名称\n  displayName                String    @map(\"display_name\") @db.VarChar(100)\n  /// 模型类型：chat-对话模型，embedding-嵌入模型，asr-音频识别模型\n  modelType                  String    @map(\"model_type\") @db.VarChar(20)\n  /// LangChain SDK 类型：openai、deepseek、gemini、anthropic\n  sdkType                    String    @default(\"openai\") @map(\"sdk_type\") @db.VarChar(20)\n  /// 模型版本\n  modelVersion               String?   @map(\"model_version\") @db.VarChar(50)\n  /// 上下文窗口大小\n  contextWindow              Int?      @map(\"context_window\")\n  /// 嵌入维度（embedding 模型专用）\n  dimensions                 Int?\n  /// 批处理大小\n  batchSize                  Int?      @map(\"batch_size\")\n  /// 是否默认：true-是，false-否\n  isDefault                  Boolean   @default(false) @map(\"is_default\")\n  /// 状态：1-启用，0-禁用\n  status                     Int       @default(1)\n  /// 优先级，数字越小优先级越高\n  priority                   Int       @default(10)\n  /// 输入成本（每百万tokens）\n  inputCostPerMillionTokens  Decimal?  @map(\"input_cost_per_million_tokens\") @db.Decimal(12, 4)\n  /// 输出成本（每百万tokens）\n  outputCostPerMillionTokens Decimal?  @map(\"output_cost_per_million_tokens\") @db.Decimal(12, 4)\n  /// 创建时间\n  createdAt                  DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt                  DateTime  @default(now()) @updatedAt @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt                  DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的提供商\n  modelProvider modelProviders @relation(fields: [providerId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的节点\n  nodes nodes[]\n\n  @@unique([providerId, name])\n  @@index([providerId], map: \"idx_models_provider_id\")\n  @@index([modelType], map: \"idx_models_model_type\")\n  @@index([isDefault], map: \"idx_models_is_default\")\n  @@index([status], map: \"idx_models_status\")\n  @@index([priority], map: \"idx_models_priority\")\n  @@index([deletedAt], map: \"idx_models_deleted_at\")\n  @@map(\"models\")\n}\n\n/// 节点分组表 - 用于组织和管理相关节点\nmodel nodeGroups {\n  /// 分组ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 分组名称\n  name        String    @db.VarChar(100)\n  /// 分组描述\n  description String?   @db.VarChar(255)\n  /// 排序优先级，数字越小越靠前\n  priority    Int       @default(100)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的节点\n  nodes nodes[]\n\n  @@index([priority], map: \"idx_node_groups_priority\")\n  @@index([deletedAt], map: \"idx_node_groups_deleted_at\")\n  @@map(\"node_groups\")\n}\n\n/// 节点表 - 工作流中的分析节点，定义分析任务的配置和行为\nmodel nodes {\n  /// 节点ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 节点名称（唯一标识，如 case_summary）\n  name         String    @unique @db.VarChar(100)\n  /// 节点显示标题\n  title        String?   @db.VarChar(100)\n  /// 节点描述\n  description  String?   @db.VarChar(255)\n  /// 节点类型：analysis-分析模块，document-文书模块，extraction-数据提取，agent-主代理\n  type         String    @db.VarChar(100)\n  /// 排序优先级，数字越小越靠前\n  priority     Int       @default(100)\n  /// 关联的模型ID\n  modelId      Int       @map(\"model_id\")\n  /// 工具列表（JSON 数组）\n  tools        Json      @default(\"[]\")\n  /// 结构化输出 schema（JSON Schema 格式，用于 extraction 类型节点）\n  outputSchema Json?     @map(\"output_schema\") @db.JsonB\n  /// 关联的分组ID\n  groupId      Int?      @map(\"group_id\")\n  /// 状态：1-启用，0-禁用\n  status       Int       @default(1)\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的分组\n  group nodeGroups? @relation(fields: [groupId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的模型\n  model models @relation(fields: [modelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的提示词\n  prompts prompts[]\n\n  /// 关联的会员节点权限\n  levelNodeAccess levelNodeAccess[]\n\n  /// 关联的案件分析结果\n  caseAnalyses caseAnalyses[]\n\n  @@index([name], map: \"idx_nodes_name\")\n  @@index([type], map: \"idx_nodes_type\")\n  @@index([priority], map: \"idx_nodes_priority\")\n  @@index([groupId], map: \"idx_nodes_group_id\")\n  @@index([modelId], map: \"idx_nodes_model_id\")\n  @@index([status], map: \"idx_nodes_status\")\n  @@index([deletedAt], map: \"idx_nodes_deleted_at\")\n  @@map(\"nodes\")\n}\n\n/// 提示词表 - 节点使用的 AI 提示词模板，支持版本管理\nmodel prompts {\n  /// 提示词ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 提示词名称\n  name      String    @db.VarChar(100)\n  /// 提示词显示标题\n  title     String?   @db.VarChar(100)\n  /// 提示词内容\n  content   String    @db.Text\n  /// 变量列表（JSON 数组，如 [\"caseInfo\", \"materials\"]）\n  variables Json      @default(\"[]\")\n  /// 版本号\n  version   String    @db.VarChar(100)\n  /// 提示词类型：system-系统提示词，user-用户提示词，assistant-助手提示词\n  type      String    @db.VarChar(100)\n  /// 状态：0-未生效，1-生效\n  status    Int       @default(0)\n  /// 关联的节点ID\n  nodeId    Int       @map(\"node_id\")\n  /// 创建时间\n  createdAt DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的节点\n  node nodes @relation(fields: [nodeId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([name], map: \"idx_prompts_name\")\n  @@index([nodeId], map: \"idx_prompts_node_id\")\n  @@index([type], map: \"idx_prompts_type\")\n  @@index([status], map: \"idx_prompts_status\")\n  @@index([deletedAt], map: \"idx_prompts_deleted_at\")\n  @@map(\"prompts\")\n}\n\n/// 会员节点权限表 - 控制不同会员级别可以访问哪些分析节点\nmodel levelNodeAccess {\n  /// 权限ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 会员级别ID\n  levelId   Int       @map(\"level_id\")\n  /// 节点ID\n  nodeId    Int       @map(\"node_id\")\n  /// 创建时间\n  createdAt DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的会员级别\n  level membershipLevels @relation(fields: [levelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的节点\n  node nodes @relation(fields: [nodeId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@unique([levelId, nodeId])\n  @@index([levelId], map: \"idx_level_node_access_level_id\")\n  @@index([nodeId], map: \"idx_level_node_access_node_id\")\n  @@index([deletedAt], map: \"idx_level_node_access_deleted_at\")\n  @@map(\"level_node_access\")\n}\n\n/// 订单表\nmodel orders {\n  /// 订单ID，主键，自增\n  id           Int       @id @default(autoincrement())\n  /// 订单号\n  orderNo      String    @unique @map(\"order_no\") @db.VarChar(32)\n  /// 用户ID\n  userId       Int       @map(\"user_id\")\n  /// 商品ID\n  productId    Int       @map(\"product_id\")\n  /// 订单金额\n  amount       Decimal   @db.Decimal(10, 2)\n  /// 购买时长\n  duration     Int\n  /// 时长单位：month/year\n  durationUnit String    @map(\"duration_unit\") @db.VarChar(10)\n  /// 订单类型：purchase-新购，upgrade-升级，renew-续费\n  orderType    String    @default(\"purchase\") @map(\"order_type\") @db.VarChar(20)\n  /// 状态：0-待支付，1-已支付，2-已取消，3-已退款\n  status       Int       @default(0)\n  /// 支付时间\n  paidAt       DateTime? @map(\"paid_at\") @db.Timestamptz(6)\n  /// 订单过期时间\n  expiredAt    DateTime  @map(\"expired_at\") @db.Timestamptz(6)\n  /// 备注\n  remark       String?   @db.VarChar(255)\n  /// 创建时间\n  createdAt    DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt    DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt    DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user                     users                      @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的商品\n  product                  products                   @relation(fields: [productId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的支付单\n  paymentTransactions      paymentTransactions[]\n  /// 关联的会员升级记录\n  membershipUpgradeRecords membershipUpgradeRecords[]\n\n  @@index([orderNo], map: \"idx_orders_order_no\")\n  @@index([userId], map: \"idx_orders_user_id\")\n  @@index([productId], map: \"idx_orders_product_id\")\n  @@index([status], map: \"idx_orders_status\")\n  @@index([expiredAt], map: \"idx_orders_expired_at\")\n  @@index([deletedAt], map: \"idx_orders_deleted_at\")\n  @@map(\"orders\")\n}\n\n/// 支付单表\nmodel paymentTransactions {\n  /// 支付单ID，主键，自增\n  id             Int       @id @default(autoincrement())\n  /// 支付单号\n  transactionNo  String    @unique @map(\"transaction_no\") @db.VarChar(32)\n  /// 关联订单ID\n  orderId        Int       @map(\"order_id\")\n  /// 支付金额\n  amount         Decimal   @db.Decimal(10, 2)\n  /// 支付渠道：wechat/alipay\n  paymentChannel String    @map(\"payment_channel\") @db.VarChar(20)\n  /// 支付方式：mini_program/scan_code/wap/app/pc\n  paymentMethod  String    @map(\"payment_method\") @db.VarChar(20)\n  /// 第三方交易号\n  outTradeNo     String?   @map(\"out_trade_no\") @db.VarChar(64)\n  /// 预支付ID（微信）\n  prepayId       String?   @map(\"prepay_id\") @db.VarChar(64)\n  /// 状态：0-待支付，1-支付成功，2-支付失败，3-已过期，4-已退款\n  status         Int       @default(0)\n  /// 支付时间\n  paidAt         DateTime? @map(\"paid_at\") @db.Timestamptz(6)\n  /// 支付单过期时间\n  expiredAt      DateTime  @map(\"expired_at\") @db.Timestamptz(6)\n  /// 回调原始数据\n  callbackData   Json?     @map(\"callback_data\")\n  /// 错误信息\n  errorMessage   String?   @map(\"error_message\") @db.VarChar(255)\n  /// 备注\n  remark         String?   @db.VarChar(255)\n  /// 创建时间\n  createdAt      DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt      DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt      DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的订单\n  order orders @relation(fields: [orderId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([transactionNo], map: \"idx_payment_transactions_transaction_no\")\n  @@index([orderId], map: \"idx_payment_transactions_order_id\")\n  @@index([outTradeNo], map: \"idx_payment_transactions_out_trade_no\")\n  @@index([status], map: \"idx_payment_transactions_status\")\n  @@index([expiredAt], map: \"idx_payment_transactions_expired_at\")\n  @@index([deletedAt], map: \"idx_payment_transactions_deleted_at\")\n  @@map(\"payment_transactions\")\n}\n\n/// 会员升级记录表\nmodel membershipUpgradeRecords {\n  /// 会员升级记录ID，主键，自增\n  id                Int       @id @default(autoincrement())\n  /// 用户ID\n  userId            Int       @map(\"user_id\")\n  /// 原会员记录ID\n  fromMembershipId  Int       @map(\"from_membership_id\")\n  /// 新会员记录ID\n  toMembershipId    Int       @map(\"to_membership_id\")\n  /// 订单ID\n  orderId           Int       @map(\"order_id\")\n  /// 升级价格\n  upgradePrice      Decimal   @map(\"upgrade_price\") @db.Decimal(10, 2)\n  /// 积分补偿\n  pointCompensation Int       @map(\"point_compensation\")\n  /// 转入积分数量（从旧会员关联积分转入）\n  transferPoints    Int       @default(0) @map(\"transfer_points\")\n  /// 升级详情（JSON，记录旧/新会员和积分记录的关联关系）\n  details           Json?     @map(\"details\")\n  /// 创建时间\n  createdAt         DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt         DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt         DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user           users           @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 原会员记录\n  fromMembership userMemberships @relation(\"FromMembership\", fields: [fromMembershipId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 新会员记录\n  toMembership   userMemberships @relation(\"ToMembership\", fields: [toMembershipId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的订单\n  order          orders          @relation(fields: [orderId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_membership_upgrade_records_user_id\")\n  @@index([fromMembershipId], map: \"idx_membership_upgrade_records_from_membership_id\")\n  @@index([toMembershipId], map: \"idx_membership_upgrade_records_to_membership_id\")\n  @@index([deletedAt], map: \"idx_membership_upgrade_records_deleted_at\")\n  @@map(\"membership_upgrade_records\")\n}\n\n/// 积分记录表\nmodel pointRecords {\n  /// 积分记录ID，主键，自增\n  id                 Int       @id @default(autoincrement())\n  /// 关联的用户ID，外键关联用户表\n  userId             Int       @map(\"user_id\")\n  /// 积分数量\n  pointAmount        Int       @map(\"point_amount\")\n  /// 已使用积分数量\n  used               Int       @map(\"used\")\n  /// 剩余积分数量\n  remaining          Int       @map(\"remaining\")\n  /// 积分来源\n  sourceType         Int       @map(\"source_type\")\n  /// 积分来源ID，根据来源类型关联到不同的表\n  sourceId           Int?      @map(\"source_id\")\n  /// 用户会员记录ID\n  userMembershipId   Int?      @map(\"user_membership_id\")\n  /// 生效时间\n  effectiveAt        DateTime  @map(\"effective_at\") @db.Timestamptz(6)\n  /// 过期时间\n  expiredAt          DateTime  @map(\"expired_at\") @db.Timestamptz(6)\n  /// 结算时间\n  settlementAt       DateTime? @map(\"settlement_at\") @db.Timestamptz(6)\n  /// 积分状态：1-有效，0-无效，2-已结算\n  status             Int       @default(1) @map(\"status\")\n  /// 转出积分数量（会员升级时记录）\n  transferOut        Int?      @default(0) @map(\"transfer_out\")\n  /// 转出目标记录ID（会员升级时指向转入积分记录）\n  transferToRecordId Int?      @map(\"transfer_to_record_id\")\n  /// 备注\n  remark             String?   @map(\"remark\")\n  /// 创建时间\n  createdAt          DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt          DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt          DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的积分消耗记录\n  pointConsumptionRecords pointConsumptionRecords[]\n\n  /// 关联的用户\n  users users @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的用户会员记录\n  userMembership userMemberships? @relation(fields: [userMembershipId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_point_records_user_id\")\n  @@index([sourceType], map: \"idx_point_records_source_type\")\n  @@index([sourceId], map: \"idx_point_records_source_id\")\n  @@index([effectiveAt], map: \"idx_point_records_effective_at\")\n  @@index([expiredAt], map: \"idx_point_records_expired_at\")\n  @@index([settlementAt], map: \"idx_point_records_settlement_at\")\n  @@index([deletedAt], map: \"idx_point_records_deleted_at\")\n  @@map(\"point_records\")\n}\n\n/// 积分消耗项目表\nmodel pointConsumptionItems {\n  /// 积分消耗项目ID，主键，自增\n  id                      Int                       @id @default(autoincrement())\n  /// 消耗项目标识符，用于代码中引用，避免硬编码 ID\n  key                     String?                   @unique @db.VarChar(50)\n  /// 分组\n  group                   String                    @db.VarChar(100)\n  /// 积分消耗项目名称\n  name                    String                    @db.VarChar(100)\n  /// 积分消耗项目描述\n  description             String?                   @db.VarChar(255)\n  /// 项目计量单位\n  unit                    String                    @db.VarChar(10)\n  /// 积分消耗数量\n  pointAmount             Int                       @map(\"point_amount\")\n  /// 积分消耗项目状态\n  status                  Int                       @default(1)\n  /// 创建时间\n  createdAt               DateTime                  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt               DateTime                  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt               DateTime?                 @map(\"deleted_at\") @db.Timestamptz(6)\n  /// 消耗折扣\n  discount                Decimal?                  @default(1) @map(\"discount\") @db.Decimal(3, 2)\n  pointConsumptionRecords pointConsumptionRecords[]\n\n  @@index([key], map: \"idx_point_consumption_items_key\")\n  @@index([name], map: \"idx_point_consumption_items_name\")\n  @@index([status], map: \"idx_point_consumption_items_status\")\n  @@index([deletedAt], map: \"idx_point_consumption_items_deleted_at\")\n  @@map(\"point_consumption_items\")\n}\n\n/// 积分消耗记录表\nmodel pointConsumptionRecords {\n  /// 积分消耗记录ID，主键，自增\n  id            Int       @id @default(autoincrement())\n  /// 关联的用户ID，外键关联用户表\n  userId        Int       @map(\"user_id\")\n  /// 关联的积分记录ID，外键关联积分记录表\n  pointRecordId Int       @map(\"point_record_id\")\n  /// 积分消耗项目ID，外键关联积分消耗项目表\n  itemId        Int       @map(\"item_id\")\n  /// 预扣批次 ID，用于关联同一次预扣操作的多条记录\n  batchId       String?   @map(\"batch_id\") @db.VarChar(36)\n  /// 积分消耗数量\n  pointAmount   Int       @map(\"point_amount\")\n  /// 积分消耗记录状态：0-无效，1-预扣，2-已结算\n  status        Int       @default(1)\n  /// 积分消耗对应项目的资源ID，根据来源类型关联到不同的表\n  sourceId      Int?      @map(\"source_id\")\n  /// 备注\n  remark        String?   @map(\"remark\")\n  /// 创建时间\n  createdAt     DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt     DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt     DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的积分消耗项目\n  pointConsumptionItems pointConsumptionItems @relation(fields: [itemId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的积分记录\n  pointRecords          pointRecords          @relation(fields: [pointRecordId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的用户\n  users                 users                 @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_point_consumption_records_user_id\")\n  @@index([itemId], map: \"idx_point_consumption_records_item_id\")\n  @@index([batchId], map: \"idx_point_consumption_records_batch_id\")\n  @@index([status], map: \"idx_point_consumption_records_status\")\n  @@index([deletedAt], map: \"idx_point_consumption_records_deleted_at\")\n  @@map(\"point_consumption_records\")\n}\n\n/// 商品表\nmodel products {\n  /// 商品ID，主键，自增\n  id                   Int       @id @default(autoincrement())\n  /// 商品名称\n  name                 String    @db.VarChar(100)\n  /// 商品描述\n  description          String?   @db.VarChar(500)\n  /// 商品类型：1-会员商品，2-积分商品\n  type                 Int\n  /// 商品分类\n  category             String?   @db.VarChar(50)\n  /// 关联会员级别ID\n  levelId              Int?      @map(\"level_id\")\n  /// 月度价格\n  priceMonthly         Decimal?  @map(\"price_monthly\") @db.Decimal(10, 2)\n  /// 年度价格\n  priceYearly          Decimal?  @map(\"price_yearly\") @db.Decimal(10, 2)\n  /// 默认售卖时长（会员专用）：1-月，2-年\n  defaultDuration      Int?      @map(\"default_duration\")\n  /// 积分单价\n  unitPrice            Decimal?  @map(\"unit_price\") @db.Decimal(10, 2)\n  /// 月度价格原价（会员专用，用于显示划线价格）\n  originalPriceMonthly Decimal?  @map(\"original_price_monthly\") @db.Decimal(10, 2)\n  /// 年度价格原价（会员专用，用于显示划线价格）\n  originalPriceYearly  Decimal?  @map(\"original_price_yearly\") @db.Decimal(10, 2)\n  /// 单价原价（积分专用，用于显示划线价格）\n  originalUnitPrice    Decimal?  @map(\"original_unit_price\") @db.Decimal(10, 2)\n  /// 最小购买数量\n  minQuantity          Int?      @default(1) @map(\"min_quantity\")\n  /// 最大购买数量\n  maxQuantity          Int?      @map(\"max_quantity\")\n  /// 购买次数限制（0-不限制）\n  purchaseLimit        Int?      @default(0) @map(\"purchase_limit\")\n  /// 积分数量\n  pointAmount          Int?      @map(\"point_amount\")\n  /// 赠送积分\n  giftPoint            Int?      @map(\"gift_point\")\n  /// 状态：1-上架，0-下架\n  status               Int       @default(1)\n  /// 排序\n  sortOrder            Int       @default(0) @map(\"sort_order\")\n  /// 创建时间\n  createdAt            DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt            DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt            DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的会员级别\n  level  membershipLevels? @relation(fields: [levelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的订单\n  orders orders[]\n\n  @@index([type], map: \"idx_products_type\")\n  @@index([levelId], map: \"idx_products_level_id\")\n  @@index([status], map: \"idx_products_status\")\n  @@index([sortOrder], map: \"idx_products_sort_order\")\n  @@index([deletedAt], map: \"idx_products_deleted_at\")\n  @@map(\"products\")\n}\n\n/// 角色表\nmodel roles {\n  /// 角色ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 角色名称\n  name        String    @unique @db.VarChar(100)\n  /// 角色标识\n  code        String    @unique @db.VarChar(100)\n  /// 角色描述\n  description String?   @db.VarChar(200)\n  /// 角色状态\n  status      Int       @default(1)\n  /// 角色创建时间\n  createdAt   DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 角色更新时间\n  updatedAt   DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 角色删除时间\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  /// 角色路由关联\n  roleRouters        roleRouters[]\n  /// 用户角色关联\n  userRoles          userRoles[]\n  /// 角色 API 权限关联\n  roleApiPermissions roleApiPermissions[]\n\n  @@index([id], map: \"idx_roles_id\")\n  @@index([name], map: \"idx_roles_name\")\n  @@index([code], map: \"idx_roles_code\")\n  @@index([description], map: \"idx_roles_description\")\n  @@index([status], map: \"idx_roles_status\")\n  @@index([createdAt], map: \"idx_roles_created_at\")\n  @@index([updatedAt], map: \"idx_roles_updated_at\")\n  @@index([deletedAt], map: \"idx_roles_deleted_at\")\n  @@map(\"roles\")\n}\n\n/// 角色路由关联表（多对多中间表）\nmodel roleRouters {\n  /// 角色路由ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 角色ID，外键关联角色表\n  roleId    Int       @map(\"role_id\")\n  /// 路由ID，外键关联路由表\n  routerId  Int       @map(\"router_id\")\n  /// 角色路由创建时间\n  createdAt DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 角色路由更新时间\n  updatedAt DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 角色路由删除时间\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  /// 关联角色\n  role   roles   @relation(fields: [roleId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  /// 关联路由\n  router routers @relation(fields: [routerId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([roleId, routerId], name: \"idx_role_router_unique\")\n  @@index([id], map: \"idx_role_routers_id\")\n  @@index([roleId], map: \"idx_role_routers_role_id\")\n  @@index([routerId], map: \"idx_role_routers_router_id\")\n  @@index([createdAt], map: \"idx_role_routers_created_at\")\n  @@index([updatedAt], map: \"idx_role_routers_updated_at\")\n  @@index([deletedAt], map: \"idx_role_routers_deleted_at\")\n  @@map(\"role_routers\")\n}\n\n/// 用户角色关联表（多对多中间表）\nmodel userRoles {\n  /// 用户角色ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 用户ID，外键关联用户表\n  userId    Int       @map(\"user_id\")\n  /// 角色ID，外键关联角色表\n  roleId    Int       @map(\"role_id\")\n  /// 创建时间\n  createdAt DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 更新时间\n  updatedAt DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  /// 关联用户\n  user users @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  /// 关联角色\n  role roles @relation(fields: [roleId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([userId, roleId], name: \"idx_user_role_unique\")\n  @@index([userId], map: \"idx_user_roles_user_id\")\n  @@index([roleId], map: \"idx_user_roles_role_id\")\n  @@index([createdAt], map: \"idx_user_roles_created_at\")\n  @@index([updatedAt], map: \"idx_user_roles_updated_at\")\n  @@index([deletedAt], map: \"idx_user_roles_deleted_at\")\n  @@map(\"user_roles\")\n}\n\n/// 文档识别记录表 - 存储 PDF 转换结果\nmodel docRecognitionRecords {\n  /// 记录ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 关联的用户ID\n  userId          Int       @map(\"user_id\")\n  /// 关联的 OSS 文件ID\n  ossFileId       Int       @map(\"oss_file_id\")\n  /// 识别状态：0-待处理，1-处理中，2-成功，3-失败\n  status          Int       @default(0)\n  /// HTML 内容\n  htmlContent     String?   @map(\"html_content\") @db.Text\n  /// Markdown 内容\n  markdownContent String?   @map(\"markdown_content\") @db.Text\n  /// 关键词（JSON 数组）\n  keywords        Json?     @default(\"[]\")\n  /// 摘要\n  summary         String?   @db.Text\n  /// 向量存储 ID 集合（JSON 数组）\n  vectorIds       Json?     @default(\"[]\") @map(\"vector_ids\")\n  /// 最后嵌入时间\n  lastEmbeddingAt DateTime? @map(\"last_embedding_at\") @db.Timestamptz(6)\n  /// 最后编辑时间\n  lastEditAt      DateTime? @map(\"last_edit_at\") @db.Timestamptz(6)\n  /// 创建时间\n  createdAt       DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt       DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user users @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_doc_recognition_records_user_id\")\n  @@index([ossFileId], map: \"idx_doc_recognition_records_oss_file_id\")\n  @@index([status], map: \"idx_doc_recognition_records_status\")\n  @@index([deletedAt], map: \"idx_doc_recognition_records_deleted_at\")\n  @@map(\"doc_recognition_records\")\n}\n\n/// 图片识别记录表 - 存储 OCR 识别结果\nmodel imageRecognitionRecords {\n  /// 记录ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 关联的用户ID\n  userId          Int       @map(\"user_id\")\n  /// 关联的 OSS 文件ID\n  ossFileId       Int       @map(\"oss_file_id\")\n  /// 识别状态：0-待处理，1-处理中，2-成功，3-失败\n  status          Int       @default(0)\n  /// 图片类型：doc-文档，photo-照片\n  imageType       String?   @map(\"image_type\") @db.VarChar(50)\n  /// HTML 内容\n  htmlContent     String?   @map(\"html_content\") @db.Text\n  /// Markdown 内容\n  markdownContent String?   @map(\"markdown_content\") @db.Text\n  /// 关键词（JSON 数组）\n  keywords        Json?     @default(\"[]\")\n  /// 摘要\n  summary         String?   @db.Text\n  /// 向量存储 ID 集合（JSON 数组）\n  vectorIds       Json?     @default(\"[]\") @map(\"vector_ids\")\n  /// 最后嵌入时间\n  lastEmbeddingAt DateTime? @map(\"last_embedding_at\") @db.Timestamptz(6)\n  /// 最后编辑时间\n  lastEditAt      DateTime? @map(\"last_edit_at\") @db.Timestamptz(6)\n  /// 创建时间\n  createdAt       DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt       DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user users @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_image_recognition_records_user_id\")\n  @@index([ossFileId], map: \"idx_image_recognition_records_oss_file_id\")\n  @@index([status], map: \"idx_image_recognition_records_status\")\n  @@index([imageType], map: \"idx_image_recognition_records_image_type\")\n  @@index([deletedAt], map: \"idx_image_recognition_records_deleted_at\")\n  @@map(\"image_recognition_records\")\n}\n\n/// ASR 任务表 - 存储语音识别任务记录\nmodel asrTasks {\n  /// 任务ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// ASR 服务返回的任务ID\n  taskId      String?   @map(\"task_id\") @db.VarChar(100)\n  /// 任务状态：0-待处理，1-处理中，2-成功，3-失败\n  status      Int       @default(0)\n  /// 是否为加密文件\n  isEncrypted Boolean   @default(false) @map(\"is_encrypted\")\n  /// 任务原始数据（提交参数等）\n  taskRawData Json?     @default(\"{}\") @map(\"task_raw_data\")\n  /// 识别结果\n  result      Json?     @default(\"{}\")\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的 ASR 识别记录\n  asrRecords asrRecords[]\n\n  @@index([taskId], map: \"idx_asr_tasks_task_id\")\n  @@index([status], map: \"idx_asr_tasks_status\")\n  @@index([deletedAt], map: \"idx_asr_tasks_deleted_at\")\n  @@map(\"asr_tasks\")\n}\n\n/// ASR 识别记录表 - 存储语音识别结果\nmodel asrRecords {\n  /// 记录ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 关联的用户ID\n  userId          Int       @map(\"user_id\")\n  /// 关联的 OSS 文件ID\n  ossFileId       Int       @map(\"oss_file_id\")\n  /// 关联的 ASR 任务ID\n  asrTasksId      Int?      @map(\"asr_tasks_id\")\n  /// 识别状态：0-待处理，1-处理中，2-成功，3-失败\n  status          Int       @default(0)\n  /// 提交的音频 URL（签名 URL 可能很长，使用 Text 类型）\n  audioUrl        String?   @map(\"audio_url\") @db.Text\n  /// 音频时长（秒）\n  audioDuration   Int?      @map(\"audio_duration\")\n  /// 识别结果\n  result          Json?     @default(\"{}\")\n  /// 转录原始 JSON 的 OSS 文件 ID\n  jsonOssFileId   Int?      @map(\"json_oss_file_id\")\n  /// 临时文件路径（加密文件解密后上传的路径，识别完成后需清理）\n  tempFilePath    String?   @map(\"temp_file_path\") @db.VarChar(500)\n  /// 说话人列表（JSON 数组）\n  speakers        Json?     @default(\"[]\")\n  /// 关键词（JSON 数组）\n  keywords        Json?     @default(\"[]\")\n  /// 摘要\n  summary         String?   @db.Text\n  /// 向量存储 ID 集合（JSON 数组）\n  vectorIds       Json?     @default(\"[]\") @map(\"vector_ids\")\n  /// 最后嵌入时间\n  lastEmbeddingAt DateTime? @map(\"last_embedding_at\") @db.Timestamptz(6)\n  /// 最后编辑时间\n  lastEditAt      DateTime? @map(\"last_edit_at\") @db.Timestamptz(6)\n  /// 创建时间\n  createdAt       DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt       DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user users @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  /// 关联的 ASR 任务\n  asrTask asrTasks? @relation(fields: [asrTasksId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_asr_records_user_id\")\n  @@index([ossFileId], map: \"idx_asr_records_oss_file_id\")\n  @@index([asrTasksId], map: \"idx_asr_records_asr_tasks_id\")\n  @@index([status], map: \"idx_asr_records_status\")\n  @@index([deletedAt], map: \"idx_asr_records_deleted_at\")\n  @@map(\"asr_records\")\n}\n\n/// MinerU Token 表 - 存储 MinerU API 访问凭证\nmodel mineruTokens {\n  /// Token ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// Token 名称\n  name      String    @db.VarChar(100)\n  /// Token 值（加密存储）\n  token     String    @db.VarChar(500)\n  /// 备注\n  remark    String?   @db.VarChar(255)\n  /// 状态：1-启用，0-禁用\n  status    Int       @default(1)\n  /// 创建时间\n  createdAt DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  @@index([status], map: \"idx_mineru_tokens_status\")\n  @@index([deletedAt], map: \"idx_mineru_tokens_deleted_at\")\n  @@map(\"mineru_tokens\")\n}\n\n/// MinerU 任务表 - 存储 PDF 转换任务记录\nmodel mineruTasks {\n  /// 任务ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// MinerU 服务返回的任务ID\n  taskId      String?   @map(\"task_id\") @db.VarChar(100)\n  /// 关联的 OSS 文件ID\n  ossFileId   Int       @map(\"oss_file_id\")\n  /// 关联的用户ID\n  userId      Int       @map(\"user_id\")\n  /// 任务状态：0-待处理，1-处理中，2-成功，3-失败\n  status      Int       @default(0)\n  /// 是否为加密文件\n  isEncrypted Boolean   @default(false) @map(\"is_encrypted\")\n  /// 任务原始数据（提交参数等）\n  taskRawData Json?     @default(\"{}\") @map(\"task_raw_data\")\n  /// 转换结果\n  result      Json?     @default(\"{}\")\n  /// 错误信息\n  errorMsg    String?   @map(\"error_msg\") @db.Text\n  /// 重试次数\n  retryCount  Int       @default(0) @map(\"retry_count\")\n  /// 完成时间\n  completedAt DateTime? @map(\"completed_at\") @db.Timestamptz(6)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user users @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([taskId], map: \"idx_mineru_tasks_task_id\")\n  @@index([ossFileId], map: \"idx_mineru_tasks_oss_file_id\")\n  @@index([userId], map: \"idx_mineru_tasks_user_id\")\n  @@index([status], map: \"idx_mineru_tasks_status\")\n  @@index([deletedAt], map: \"idx_mineru_tasks_deleted_at\")\n  @@map(\"mineru_tasks\")\n}\n\n/// 兑换码表\nmodel redemptionCodes {\n  /// 兑换码ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 兑换码\n  code        String    @unique @db.VarChar(32)\n  /// 兑换类型：1-仅会员，2-仅积分，3-会员和积分\n  type        Int\n  /// 会员级别ID\n  levelId     Int?      @map(\"level_id\")\n  /// 会员时长（天）\n  duration    Int?\n  /// 积分数量\n  pointAmount Int?      @map(\"point_amount\")\n  /// 过期时间\n  expiredAt   DateTime? @map(\"expired_at\") @db.Timestamptz(6)\n  /// 状态：1-有效，2-已使用，3-已过期，4-已作废\n  status      Int       @default(1)\n  /// 备注\n  remark      String?   @db.VarChar(255)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的会员级别\n  level             membershipLevels?   @relation(fields: [levelId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的兑换记录\n  redemptionRecords redemptionRecords[]\n\n  @@index([code], map: \"idx_redemption_codes_code\")\n  @@index([status], map: \"idx_redemption_codes_status\")\n  @@index([expiredAt], map: \"idx_redemption_codes_expired_at\")\n  @@index([deletedAt], map: \"idx_redemption_codes_deleted_at\")\n  @@map(\"redemption_codes\")\n}\n\n/// 兑换记录表\nmodel redemptionRecords {\n  /// 兑换记录ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 用户ID\n  userId    Int       @map(\"user_id\")\n  /// 兑换码ID\n  codeId    Int       @map(\"code_id\")\n  /// 创建时间\n  createdAt DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  /// 关联的用户\n  user users           @relation(fields: [userId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 关联的兑换码\n  code redemptionCodes @relation(fields: [codeId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n\n  @@index([userId], map: \"idx_redemption_records_user_id\")\n  @@index([codeId], map: \"idx_redemption_records_code_id\")\n  @@index([deletedAt], map: \"idx_redemption_records_deleted_at\")\n  @@map(\"redemption_records\")\n}\n\n/// 路由表\nmodel routers {\n  /// 路由ID，主键，自增\n  id            Int       @id @default(autoincrement())\n  /// 路由名称\n  name          String    @unique @db.VarChar(100)\n  /// 路由标题\n  title         String    @db.VarChar(100)\n  /// 路由描述\n  description   String?   @db.VarChar(200)\n  /// 路由路径\n  path          String    @unique @db.VarChar(200)\n  /// 是否在菜单中显示\n  isMenu        Boolean   @default(false) @map(\"is_menu\")\n  /// 父级路由ID，null表示顶级路由\n  parentId      Int?      @map(\"parent_id\")\n  /// 路由图标\n  icon          String?   @db.VarChar(100)\n  /// 路由组ID，外键关联路由组表\n  groupId       Int       @default(0) @map(\"group_id\")\n  /// 路由排序\n  sort          Int       @default(0)\n  /// 菜单分组名称（如\"权限管理\"、\"运营管理\"）\n  menuGroup     String?   @map(\"menu_group\") @db.VarChar(100)\n  /// 菜单分组排序\n  menuGroupSort Int       @default(0) @map(\"menu_group_sort\")\n  /// 路由创建时间\n  createdAt     DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 路由更新时间\n  updatedAt     DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 路由删除时间\n  deletedAt     DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  /// 关联路由组\n  routerGroups routerGroups? @relation(fields: [groupId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 父路由（自引用）\n  parent       routers?      @relation(\"RouterTree\", fields: [parentId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  /// 子路由列表（自引用）\n  children     routers[]     @relation(\"RouterTree\")\n  /// 角色路由关联\n  roleRouters  roleRouters[]\n\n  @@index([groupId], map: \"idx_routers_group_id\")\n  @@index([parentId], map: \"idx_routers_parent_id\")\n  @@index([menuGroup], map: \"idx_routers_menu_group\")\n  @@index([menuGroupSort], map: \"idx_routers_menu_group_sort\")\n  @@index([createdAt], map: \"idx_routers_created_at\")\n  @@index([updatedAt], map: \"idx_routers_updated_at\")\n  @@index([deletedAt], map: \"idx_routers_deleted_at\")\n  @@map(\"routers\")\n}\n\n/// 路由组表\nmodel routerGroups {\n  /// 路由组ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 路由组名称\n  name        String    @unique @db.VarChar(100)\n  /// 路由组描述\n  description String?   @db.VarChar(200)\n  /// 路由组排序\n  sort        Int       @default(0)\n  /// 路由组状态\n  status      Int       @default(1)\n  /// 路由组创建时间\n  createdAt   DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 路由组更新时间\n  updatedAt   DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 路由组删除时间\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  routers routers[]\n\n  @@index([id], map: \"idx_router_groups_id\")\n  @@index([name], map: \"idx_router_groups_name\")\n  @@index([description], map: \"idx_router_groups_description\")\n  @@index([sort], map: \"idx_router_groups_sort\")\n  @@index([status], map: \"idx_router_groups_status\")\n  @@index([createdAt], map: \"idx_router_groups_created_at\")\n  @@index([updatedAt], map: \"idx_router_groups_updated_at\")\n  @@index([deletedAt], map: \"idx_router_groups_deleted_at\")\n  @@map(\"router_groups\")\n}\n\n/// 短信验证码表\nmodel smsRecords {\n  /// 短信验证码ID，主键，uuid\n  id        String    @id @default(uuid(7)) @db.Uuid\n  /// 手机号\n  phone     String    @db.VarChar(11)\n  /// 验证码\n  code      String    @db.VarChar(10)\n  /// 验证码类型\n  type      String    @db.VarChar(100)\n  /// 过期时间\n  expiredAt DateTime  @map(\"expired_at\") @db.Timestamptz()\n  /// 创建时间\n  createdAt DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 最后更新时间\n  updatedAt DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  @@unique([phone, type], name: \"idx_sms_phone_type\")\n  @@index([id], map: \"idx_sms_id\")\n  @@index([phone], map: \"idx_sms_phone\")\n  @@index([expiredAt], map: \"idx_sms_expired_at\")\n  @@index([type], map: \"idx_sms_type\")\n  @@index([updatedAt], map: \"idx_sms_updated_at\")\n  @@index([createdAt], map: \"idx_sms_created_at\")\n  @@index([deletedAt], map: \"idx_sms_deleted_at\")\n  @@map(\"sms_records\")\n}\n\n/// 存储配置表\n/// 用于存储用户自定义的云存储服务配置\nmodel storageConfigs {\n  /// ID，主键，自增\n  id        Int       @id @default(autoincrement())\n  /// 关联的用户ID，NULL 表示系统配置\n  userId    Int?      @map(\"user_id\")\n  /// 配置名称\n  name      String    @db.VarChar(100)\n  /// 服务商类型：aliyun_oss, qiniu, tencent_cos\n  type      String    @db.VarChar(50)\n  /// 加密存储的配置信息（JSON 格式）\n  config    Json\n  /// 是否为默认配置\n  isDefault Boolean   @default(false) @map(\"is_default\")\n  /// 是否启用\n  enabled   Boolean   @default(true)\n  /// 创建时间\n  createdAt DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为 NULL 表示未删除\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  @@index([userId], map: \"idx_storage_configs_user_id\")\n  @@index([type], map: \"idx_storage_configs_type\")\n  @@index([isDefault], map: \"idx_storage_configs_is_default\")\n  @@index([enabled], map: \"idx_storage_configs_enabled\")\n  @@index([deletedAt], map: \"idx_storage_configs_deleted_at\")\n  @@map(\"storage_configs\")\n}\n\n/// 系统配置表\nmodel systemConfigs {\n  /// 配置ID，主键，自增\n  id          Int       @id @default(autoincrement())\n  /// 配置组\n  configGroup String    @map(\"config_group\") @db.VarChar(50)\n  /// 配置名称\n  key         String    @db.VarChar(100)\n  /// 配置值\n  value       Json\n  /// 配置描述\n  description String?   @db.VarChar(255)\n  /// 状态：1-启用，0-禁用\n  status      Int       @default(1)\n  /// 创建时间\n  createdAt   DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n  /// 最后更新时间\n  updatedAt   DateTime  @default(now()) @map(\"updated_at\") @db.Timestamptz(6)\n  /// 删除时间，为NULL表示未删除\n  deletedAt   DateTime? @map(\"deleted_at\") @db.Timestamptz(6)\n\n  @@unique([configGroup, key])\n  @@index([configGroup], map: \"idx_system_configs_config_group\")\n  @@index([key], map: \"idx_system_configs_key\")\n  @@index([status], map: \"idx_system_configs_status\")\n  @@index([deletedAt], map: \"idx_system_configs_deleted_at\")\n  @@map(\"system_configs\")\n}\n\n/// 用户表\nmodel users {\n  /// 用户ID，主键，自增\n  id              Int       @id @default(autoincrement())\n  /// 用户姓名\n  name            String    @db.VarChar(100)\n  /// 用户名，可选\n  username        String?   @unique @db.VarChar(100)\n  /// 电子邮箱，可选\n  email           String?   @unique @db.VarChar(100)\n  /// 手机号，唯一标识\n  phone           String    @unique @db.VarChar(11)\n  /// 密码，加密存储\n  password        String?   @db.VarChar(100)\n  /// 用户状态：1-启用，0-禁用\n  status          Int       @default(1)\n  /// 所属公司/律所，可选\n  company         String?   @db.VarChar(100)\n  /// 个人简介，可选\n  profile         String?\n  /// 邀请码，唯一\n  inviteCode      String?   @unique @map(\"invite_code\") @db.VarChar(10)\n  /// 邀请人用户ID，外键关联用户表\n  invitedBy       Int?      @map(\"invited_by\")\n  /// 微信小程序openid\n  openid          String?   @map(\"openid\") @db.VarChar(100)\n  /// 微信小程序unionid\n  unionid         String?   @map(\"unionid\") @db.VarChar(100)\n  /// 用户注册渠道\n  registerChannel String?   @map(\"register_channel\") @db.VarChar(100)\n  /// 创建时间\n  createdAt       DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 最后更新时间\n  updatedAt       DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间\n  deletedAt       DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  /// 用户角色关联（多对多）\n  userRoles userRoles[]\n\n  /// 用户积分记录（一对多）\n  pointRecords pointRecords[]\n\n  /// 用户积分消耗记录（一对多）\n  pointConsumptionRecords pointConsumptionRecords[]\n\n  /// 用户会员记录（一对多）\n  userMemberships userMemberships[]\n\n  /// 用户兑换记录（一对多）\n  redemptionRecords redemptionRecords[]\n\n  /// 用户订单（一对多）\n  orders orders[]\n\n  /// 用户会员升级记录（一对多）\n  membershipUpgradeRecords membershipUpgradeRecords[]\n\n  /// 权限审计日志（一对多）\n  permissionAuditLogs permissionAuditLogs[]\n\n  /// 用户权益记录（一对多）\n  userBenefits userBenefits[]\n\n  /// 用户案件（一对多）\n  cases cases[]\n\n  /// 关联的会话（case 域 + assistant 域）\n  caseSessions caseSessions[]\n\n  /// 用户文档识别记录（一对多）\n  docRecognitionRecords docRecognitionRecords[]\n\n  /// 用户图片识别记录（一对多）\n  imageRecognitionRecords imageRecognitionRecords[]\n\n  /// 用户 ASR 识别记录（一对多）\n  asrRecords asrRecords[]\n\n  /// 用户 MinerU 任务（一对多）\n  mineruTasks mineruTasks[]\n\n  @@index([id], map: \"idx_users_id\")\n  @@index([status], map: \"idx_users_status\")\n  @@index([deletedAt], map: \"idx_users_deleted_at\")\n  @@map(\"users\")\n}\n\n/// token 黑名单\nmodel tokenBlacklist {\n  /// token 黑名单ID，主键，uuid\n  id        String    @id @default(uuid(7)) @db.Uuid\n  /// tokenS\n  token     String?   @db.Text()\n  /// 用户ID\n  userId    Int       @map(\"user_id\")\n  /// 过期时间\n  expiredAt DateTime  @map(\"expired_at\") @db.Timestamptz()\n  /// 创建时间\n  createdAt DateTime? @default(now()) @map(\"created_at\") @db.Timestamptz()\n  /// 最后更新时间\n  updatedAt DateTime? @default(now()) @map(\"updated_at\") @db.Timestamptz()\n  /// 删除时间\n  deletedAt DateTime? @map(\"deleted_at\") @db.Timestamptz()\n\n  @@index([userId], map: \"idx_token_blacklist_user_id\")\n  @@index([expiredAt], map: \"idx_token_blacklist_expired_at\")\n  @@index([token], map: \"idx_token_blacklist_token\")\n  @@index([createdAt], map: \"idx_token_blacklist_created_at\")\n  @@index([updatedAt], map: \"idx_token_blacklist_updated_at\")\n  @@index([deletedAt], map: \"idx_token_blacklist_deleted_at\")\n  @@map(\"token_blacklist\")\n}\n\n// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n",
